# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

```C#
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using System.Threading.Tasks;

public class EventBookingService
{
    private readonly EventDbContext _context;

    public EventBookingService(EventDbContext context)
    {
        _context = context;
    }

    public async Task<bool> BookTickets(int eventId, int ticketCount)
    {
        // Get event entity
        var @event = await _context.Events.FindAsync(eventId);

        // Check if enough seats are available
        if (event.AvailableSeats < ticketCount)
        {
            return false;
        }

        // Update inventory
        event.AvailableSeats -= ticketCount;

        // Mark ticket as purchased
        var ticket = new Ticket { EventId = eventId };
        _context.Tickets.Add(ticket);

        try
        {
            await _context.SaveChangesAsync();
        }
        catch (DbUpdateConcurrencyException)
        {
            // Handle concurrency conflict
            return false;
        }

        return true;
    }
}
